//! Claude Code env writer — `~/.config/llamastash/claude-code.sh`.
//!
//! Drops a sourceable POSIX-sh script with the Anthropic-shape vars so
//! Claude Code (and the Anthropic SDK) route through llamastash's proxy:
//!
//! - `ANTHROPIC_BASE_URL` — the proxy origin **without** the `/v1`
//!   suffix the OpenAI snippet carries; the Anthropic SDK appends
//!   `/v1/messages` itself.
//! - `ANTHROPIC_AUTH_TOKEN` — sent as `Authorization: Bearer`. We use
//!   the auth-token form (not `ANTHROPIC_API_KEY`) so Claude Code
//!   doesn't surface its custom-API-key approval prompt; the proxy
//!   accepts it (and ignores it on the keyless loopback default).
//! - `ANTHROPIC_MODEL` / `ANTHROPIC_SMALL_FAST_MODEL` — pinned to the
//!   chosen local model so Claude Code's main *and* background calls
//!   resolve through the proxy instead of its built-in `claude-*`
//!   names. Omitted for an embedding model (Claude Code can't drive one).
//!
//! Deliberately a **separate sourceable file** rather than a write into
//! Claude Code's `~/.claude/settings.json`: that file's `env` block
//! applies to *every* Claude Code session, so persisting
//! `ANTHROPIC_BASE_URL` there would silently redirect the user's real
//! Anthropic models to the local proxy. Sourcing this snippet (or
//! prefixing one `claude` invocation) is per-shell and opt-in — bare
//! `claude` stays on Anthropic. Kept separate from the OpenAI
//! [`super::env_sh`] writer so a user can pick one without the other.
//!
//! Mode is `0o600` — when the proxy enforces auth this file carries
//! the real bearer token (`ANTHROPIC_AUTH_TOKEN`), a secret, so it
//! stays user-only-readable.

use std::path::PathBuf;

use crate::init::external::{Format, PatchContext, ToolPatcher};

pub struct ClaudeCode;

/// Strip the OpenAI-style `/v1` suffix off the shared proxy base URL.
/// Claude Code / the Anthropic SDK append `/v1/messages` themselves, so
/// `ANTHROPIC_BASE_URL` must be the bare origin.
fn anthropic_base(proxy_base_url: &str) -> &str {
  let trimmed = proxy_base_url.trim_end_matches('/');
  trimmed.strip_suffix("/v1").unwrap_or(trimmed)
}

impl ToolPatcher for ClaudeCode {
  fn id(&self) -> &'static str {
    "claude-code"
  }
  fn display_name(&self) -> &'static str {
    "Claude Code"
  }
  fn default_path(&self) -> Option<PathBuf> {
    crate::util::paths::config_dir().map(|d| d.join("claude-code.sh"))
  }
  fn format(&self) -> Format {
    Format::Raw
  }
  fn build_additions(&self, _ctx: &PatchContext) -> serde_json::Value {
    // Unused for Format::Raw — present to satisfy the trait.
    serde_json::Value::Null
  }
  fn raw_body(&self, ctx: &PatchContext) -> Option<String> {
    let key = &ctx.api_key;
    let anthropic_url = anthropic_base(&ctx.proxy_base_url);
    let model = match &ctx.model_id {
      Some(id) if !ctx.is_embed => format!(
        "export ANTHROPIC_MODEL=\"{id}\"\n\
         export ANTHROPIC_SMALL_FAST_MODEL=\"{id}\"\n"
      ),
      _ => String::new(),
    };
    Some(format!(
      "#!/bin/sh\n\
       # Generated by `llamastash init`. Edits will be overwritten on re-run.\n\
       # Point Claude Code at the local proxy for this shell only:\n\
       #   source {path} && claude\n\
       # (bare `claude` keeps using your real Anthropic models.)\n\
       \n\
       export ANTHROPIC_BASE_URL=\"{anthropic_url}\"\n\
       export ANTHROPIC_AUTH_TOKEN=\"{key}\"\n\
       {model}",
      path = self
        .default_path()
        .map(|p| p.display().to_string())
        .unwrap_or_else(|| "~/.config/llamastash/claude-code.sh".into()),
    ))
  }
}

#[cfg(test)]
mod tests {
  use super::*;
  use crate::init::external::apply;

  fn ctx() -> PatchContext {
    PatchContext {
      proxy_base_url: "http://127.0.0.1:11435/v1".into(),
      api_key: "llamastash".into(),
      model_id: Some("qwen3-coder-30b".into()),
      is_embed: false,
    }
  }

  #[test]
  fn base_url_drops_the_v1_suffix() {
    assert_eq!(
      anthropic_base("http://127.0.0.1:11435/v1"),
      "http://127.0.0.1:11435"
    );
    assert_eq!(
      anthropic_base("http://127.0.0.1:11435/v1/"),
      "http://127.0.0.1:11435"
    );
    assert_eq!(anthropic_base("http://host:9000"), "http://host:9000");
  }

  #[test]
  fn writes_anthropic_snippet() {
    let dir = crate::util::test_temp::unique_temp_dir("claude-write");
    let path = dir.join("claude-code.sh");
    apply(&ClaudeCode, &ctx(), Some(path.clone())).expect("apply");
    let body = std::fs::read_to_string(&path).unwrap();
    assert!(body.starts_with("#!/bin/sh"));
    // Base URL drops /v1 (the SDK appends /v1/messages).
    assert!(body.contains("export ANTHROPIC_BASE_URL=\"http://127.0.0.1:11435\""));
    assert!(body.contains("export ANTHROPIC_AUTH_TOKEN=\"llamastash\""));
    // Chat model pins both main and small/fast.
    assert!(body.contains("export ANTHROPIC_MODEL=\"qwen3-coder-30b\""));
    assert!(body.contains("export ANTHROPIC_SMALL_FAST_MODEL=\"qwen3-coder-30b\""));
    // Stays Anthropic-only — no OpenAI vars leak in.
    assert!(!body.contains("OPENAI_"));
    std::fs::remove_dir_all(&dir).ok();
  }

  #[test]
  fn omits_model_for_embedder_or_when_unknown() {
    // No model id → base + token only, no model pins.
    let mut c = ctx();
    c.model_id = None;
    let no_model_body = ClaudeCode.raw_body(&c).unwrap();
    assert!(no_model_body.contains("export ANTHROPIC_BASE_URL="));
    assert!(!no_model_body.contains("ANTHROPIC_MODEL"));
    // Embedder → still no model pins (Claude Code can't use one).
    let mut embed = ctx();
    embed.model_id = Some("nomic-embed-text-v1.5".into());
    embed.is_embed = true;
    let embed_body = ClaudeCode.raw_body(&embed).unwrap();
    assert!(!embed_body.contains("ANTHROPIC_MODEL"));
  }

  #[cfg(unix)]
  #[test]
  fn unix_mode_is_600_may_hold_a_secret() {
    use std::os::unix::fs::PermissionsExt;
    let dir = crate::util::test_temp::unique_temp_dir("claude-mode");
    let path = dir.join("claude-code.sh");
    apply(&ClaudeCode, &ctx(), Some(path.clone())).expect("apply");
    let mode = std::fs::metadata(&path).unwrap().permissions().mode() & 0o777;
    assert_eq!(mode, 0o600);
    std::fs::remove_dir_all(&dir).ok();
  }
}
